#requires -Version 5.1
<# Created by Dewald Pretorius. Read-only Active Directory posture validator. #>
[CmdletBinding()]param([ValidateRange(1,3650)][int]$InactiveDays=90,[string]$OutputPath=(Join-Path ([Environment]::GetFolderPath('Desktop')) 'AD_Security_Posture_Validation'))
$ErrorActionPreference='Stop';New-Item -ItemType Directory $OutputPath -Force|Out-Null;$s=Get-Date -Format yyyyMMdd_HHmmss
try{Import-Module ActiveDirectory -ErrorAction Stop;$domain=Get-ADDomain;$policy=Get-ADDefaultDomainPasswordPolicy;$admins=@(Get-ADGroupMember 'Domain Admins' -Recursive|Get-ADUser -Properties Enabled,PasswordNeverExpires,LastLogonDate|Select-Object SamAccountName,Enabled,PasswordNeverExpires,LastLogonDate);$cutoff=(Get-Date).AddDays(-$InactiveDays);$findings=@($admins|Where-Object{$_.Enabled-and($_.PasswordNeverExpires-or-not$_.LastLogonDate-or$_.LastLogonDate-lt$cutoff)});[ordered]@{Generated=(Get-Date);Domain=$domain.DNSRoot;PasswordPolicy=$policy;DomainAdmins=$admins;FindingCount=$findings.Count;Findings=$findings}|ConvertTo-Json -Depth 7|Set-Content (Join-Path $OutputPath "ad_posture_$s.json");if($findings.Count-or$policy.MinPasswordLength-lt12){exit 1};exit 0}catch{Write-Error $_;exit 5}
